import { Component, OnInit } from '@angular/core';
import { AuthService } from '../../services/auth.service';
import { BookService } from '../../services/book.service';

@Component({
  selector: 'app-book-management',
  templateUrl: './book-management.component.html',
  styleUrls: ['./book-management.component.css']
})
export class BookManagementComponent implements OnInit {
  books: any[] = [];
  filteredBooks: any[] = [];
  isLoading: boolean = false;
  searchTerm: string = '';

  // Form data
  bookForm = {
    id: '',
    title: '',
    author: '',
    category: '',
    quantity: 1
  };

  isEditing: boolean = false;
  showAddForm: boolean = false;
  errorMessage: string = '';
  successMessage: string = '';

  constructor(private bookService: BookService) {}

  ngOnInit(): void {
    this.loadBooks();
  }

  loadBooks(): void {
    this.books = this.bookService.getBooks();
    this.filteredBooks = [...this.books];
  }

  searchBooks(): void {
    if (!this.searchTerm) {
      this.filteredBooks = [...this.books];
    } else {
      this.filteredBooks = this.bookService.searchBooks({
        title: this.searchTerm,
        author: this.searchTerm,
        category: this.searchTerm
      });
    }
  }

  showAddBookForm(): void {
    this.resetForm();
    this.showAddForm = true;
    this.isEditing = false;
  }

  editBook(book: any): void {
    this.bookForm = {
      id: book.id,
      title: book.title,
      author: book.author,
      category: book.category,
      quantity: book.quantity
    };
    this.isEditing = true;
    this.showAddForm = true;
  }

  saveBook(): void {
    this.errorMessage = '';
    this.successMessage = '';

    if (!this.bookForm.title || !this.bookForm.author || !this.bookForm.category) {
      this.errorMessage = 'Please fill in all fields';
      return;
    }

    if (this.bookForm.quantity < 1) {
      this.errorMessage = 'Quantity must be at least 1';
      return;
    }

    this.isLoading = true;

    if (this.isEditing) {
      const result = this.bookService.updateBook(this.bookForm.id, {
        title: this.bookForm.title,
        author: this.bookForm.author,
        category: this.bookForm.category,
        quantity: this.bookForm.quantity
      });

      if (result.success) {
        this.successMessage = result.message;
        this.loadBooks();
      } else {
        this.errorMessage = result.message;
      }
    } else {
      const result = this.bookService.addBook({
        title: this.bookForm.title,
        author: this.bookForm.author,
        category: this.bookForm.category,
        quantity: this.bookForm.quantity
      });

      if (result.success) {
        this.successMessage = result.message;
        this.loadBooks();
      } else {
        this.errorMessage = result.message;
      }
    }

    this.isLoading = false;

    if (this.successMessage) {
      setTimeout(() => {
        this.cancelForm();
      }, 2000);
    }
  }

  deleteBook(bookId: string): void {
    if (confirm('Are you sure you want to delete this book?')) {
      const result = this.bookService.deleteBook(bookId);

      if (result.success) {
        this.successMessage = result.message;
        this.loadBooks();
        setTimeout(() => {
          this.successMessage = '';
        }, 3000);
      } else {
        this.errorMessage = result.message;
        setTimeout(() => {
          this.errorMessage = '';
        }, 3000);
      }
    }
  }

  cancelForm(): void {
    this.resetForm();
    this.showAddForm = false;
    this.isEditing = false;
    this.errorMessage = '';
    this.successMessage = '';
  }

  resetForm(): void {
    this.bookForm = {
      id: '',
      title: '',
      author: '',
      category: '',
      quantity: 1
    };
  }

  clearMessages(): void {
    this.errorMessage = '';
    this.successMessage = '';
  }
}
<div class="book-management-container">
  <div class="page-header">
    <h1>📚 Book Management</h1>
    <p>Manage library books - Add, edit, delete books</p>
  </div>

  <!-- Search and Add Section -->
  <div class="actions-section">
    <div class="search-bar">
      <input 
        type="text" 
        placeholder="Search books by title, author, or category..." 
        [(ngModel)]="searchTerm" 
        (input)="searchBooks()"
        class="search-input"
      />
      <button class="search-btn">🔍 Search</button>
    </div>

    <button class="add-book-btn" (click)="showAddBookForm()" *ngIf="!showAddForm">
      ➕ Add New Book
    </button>
  </div>

  <!-- Messages -->
  <div class="message-container">
    <div class="error-message" *ngIf="errorMessage">
      {{ errorMessage }}
      <button class="close-btn" (click)="clearMessages()">×</button>
    </div>

    <div class="success-message" *ngIf="successMessage">
      {{ successMessage }}
      <button class="close-btn" (click)="clearMessages()">×</button>
    </div>
  </div>

  <!-- Add/Edit Book Form -->
  <div class="book-form" *ngIf="showAddForm">
    <div class="form-card">
      <h2>{{ isEditing ? 'Edit Book' : 'Add New Book' }}</h2>

      <form (ngSubmit)="saveBook()">
        <div class="form-row">
          <div class="form-group">
            <label for="title">Book Title *</label>
            <input 
              type="text" 
              id="title" 
              name="title" 
              [(ngModel)]="bookForm.title" 
              required 
              placeholder="Enter book title"
            />
          </div>

          <div class="form-group">
            <label for="author">Author *</label>
            <input 
              type="text" 
              id="author" 
              name="author" 
              [(ngModel)]="bookForm.author" 
              required 
              placeholder="Enter author name"
            />
          </div>
        </div>

        <div class="form-row">
          <div class="form-group">
            <label for="category">Category *</label>
            <select id="category" name="category" [(ngModel)]="bookForm.category" required>
              <option value="">Select category</option>
              <option value="Programming">Programming</option>
              <option value="Software Engineering">Software Engineering</option>
              <option value="Database">Database</option>
              <option value="Web Development">Web Development</option>
              <option value="Mobile Development">Mobile Development</option>
              <option value="Data Science">Data Science</option>
              <option value="Artificial Intelligence">Artificial Intelligence</option>
              <option value="Computer Science">Computer Science</option>
              <option value="Mathematics">Mathematics</option>
              <option value="Physics">Physics</option>
              <option value="Chemistry">Chemistry</option>
              <option value="Biology">Biology</option>
              <option value="Literature">Literature</option>
              <option value="History">History</option>
              <option value="Other">Other</option>
            </select>
          </div>

          <div class="form-group">
            <label for="quantity">Quantity *</label>
            <input 
              type="number" 
              id="quantity" 
              name="quantity" 
              [(ngModel)]="bookForm.quantity" 
              required 
              min="1"
              placeholder="Enter quantity"
            />
          </div>
        </div>

        <div class="form-actions">
          <button type="submit" class="save-btn" [disabled]="isLoading">
            <span *ngIf="!isLoading">{{ isEditing ? 'Update Book' : 'Add Book' }}</span>
            <span *ngIf="isLoading">Saving...</span>
          </button>
          <button type="button" class="cancel-btn" (click)="cancelForm()">Cancel</button>
        </div>
      </form>
    </div>
  </div>

  <!-- Books Table -->
  <div class="books-table-container">
    <div class="table-header">
      <h2>Books List ({{ filteredBooks.length }})</h2>
    </div>

    <div *ngIf="filteredBooks.length === 0" class="empty-state">
      <p>No books found</p>
    </div>

    <div class="books-table" *ngIf="filteredBooks.length > 0">
      <table>
        <thead>
          <tr>
            <th>Book Title</th>
            <th>Author</th>
            <th>Category</th>
            <th>Total Quantity</th>
            <th>Available</th>
            <th>Issued</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          <tr *ngFor="let book of filteredBooks">
            <td class="book-title">{{ book.title }}</td>
            <td>{{ book.author }}</td>
            <td>
              <span class="category-badge">{{ book.category }}</span>
            </td>
            <td>{{ book.quantity }}</td>
            <td class="available-count">{{ book.availableQuantity }}</td>
            <td>{{ book.quantity - book.availableQuantity }}</td>
            <td class="actions">
              <button class="edit-btn" (click)="editBook(book)" title="Edit Book">
                ✏️ Edit
              </button>
              <button class="delete-btn" (click)="deleteBook(book.id)" title="Delete Book">
                🗑️ Delete
              </button>
            </td>
          </tr>
        </tbody>
      </table>
    </div>
  </div>
</div>
